## 7. Retryable Error Detection

**Location:** Lines 632-652 in ai-provider.js

```javascript
isRetryable(err) {
  // Network/timeout errors
  if (err.code === 'ETIMEDOUT' || err.code === 'ECONNREFUSED' || 
      err.code === 'ECONNRESET' || err.code === 'ENOTFOUND') return true;
  if (err.message && (err.message.includes('timeout') || 
                       err.message.includes('ETIMEDOUT'))) return true;

  // HTTP status codes (400, 401, 402, 404, 429, 500, 502, 503, 504)
  const status = err.status || err.statusCode || (err.response && err.response.status);
  if (status && RETRYABLE_STATUS.has(status)) return true;

  // OpenAI SDK-specific error types
  if (err.type === 'insufficient_quota' || err.code === 'insufficient_quota') return true;
  if (err.type === 'rate_limit_exceeded' || err.code === 'rate_limit_exceeded') return true;

  // Anthropic-specific
  if (err.error && err.error.type === 'overloaded_error') return true;

  // Polsia proxy wraps upstream provider errors as proxy_error
  if (err.code === 'proxy_error' || (err.error && err.error.code === 'proxy_error')) return true;

  return false;
}
```

